function processOrder(items, customerId) {
  let total = 0;
  for (let i = 0; i < items.length; i++) {
    total = total + items[i].price * items[i].qty;
  }
  const IVA_RATE = 0.19;
  const totalConIva = total * (1 + IVA_RATE);
  return {
    total: totalConIva,
    cliente: customerId,
  };
}

