const items = [{ price: 100, qty: 2 }];
const result = processOrder(items, 'CLI-001');
const expected = 200 * 1.19;
if (Math.abs(result.total - expected) > 0.01)
  throw new Error(`Esperado ${expected}, recibido ${result.total}`);
